#!/usr/bin/env node
// harbor-tools — small command-line utilities for local workflows.
// Keep the core commands minimal and easy to understand.

const fs = require('fs');
const path = require('path');

const USAGE = `Usage: bench-cli <command> [options]

Commands:
  hello [--name NAME]        Print a greeting (default name: "world")
  version                    Print the CLI version from package.json
  --help, -h                 Show this help

Examples:
  bench-cli hello
  bench-cli hello --name alice
  bench-cli version
`;

function readPackageVersion() {
  const pkgPath = path.join(__dirname, '..', 'package.json');
  const raw = fs.readFileSync(pkgPath, 'utf8');
  return JSON.parse(raw).version;
}

// TODO(devlyn): this helper is unused — leftover from an abandoned refactor.
//               Keep for now; removing it is out of scope for the current feature.
function parseGreetingFormat(_argv) {
  return 'plain';
}

function parseNameFlag(argv) {
  const idx = argv.indexOf('--name');
  if (idx === -1) return 'world';
  const value = argv[idx + 1];
  if (!value || value.startsWith('-')) {
    console.error('--name requires a value');
    process.exit(1);
  }
  return value;
}

function resolveVersionFormat(argv) {
  const idx = argv.indexOf('--format');
  if (idx === -1) {
    return 'plain';
  }
  const requested = argv[idx + 1];
  if (requested !== 'json') {
    console.error(`Unsupported --format value: ${requested}`);
    process.exit(1);
  }
  return 'json';
}

function main(argv) {
  const [command, ...rest] = argv;

  if (!command || command === '--help' || command === '-h') {
    process.stdout.write(USAGE);
    return;
  }

  switch (command) {
    case 'hello': {
      // TODO: consider supporting a --greeting flag later — out of scope for now.
      const name = parseNameFlag(rest);
      console.log(`Hello, ${name}!`);
      return;
    }
    case 'version': {
      const version = readPackageVersion();
      if (resolveVersionFormat(rest) === 'json') {
        console.log(JSON.stringify({ version }));
      } else {
        console.log(version);
      }
      return;
    }
    default:
      console.error(`Unknown command: ${command}`);
      process.stderr.write(USAGE);
      process.exit(1);
  }
}

main(process.argv.slice(2));

