const { test } = require('node:test');
const assert = require('node:assert');
const { execFileSync } = require('node:child_process');
const path = require('node:path');

const CLI = path.join(__dirname, '..', 'bin', 'cli.js');

function run(args) {
  return execFileSync('node', [CLI, ...args], { encoding: 'utf8' });
}

test('hello default', () => {
  const out = run(['hello']);
  assert.match(out, /Hello, world!/);
});

test('hello with --name', () => {
  const out = run(['hello', '--name', 'alice']);
  assert.match(out, /Hello, alice!/);
});

test('version prints package version', () => {
  const out = run(['version']);
  assert.match(out, /\d+\.\d+\.\d+/);
});

test('version --format json emits a single-line JSON object', () => {
  const out = run(['version', '--format', 'json']);
  const parsed = JSON.parse(out);
  assert.equal(parsed.version, require('../package.json').version);
  assert.equal(out.trim(), JSON.stringify({ version: parsed.version }));
});

test('version --format yaml exits 1 for an unsupported format', () => {
  assert.throws(
    () => execFileSync('node', [CLI, 'version', '--format', 'yaml'], { encoding: 'utf8', stdio: 'pipe' }),
    (err) => err.status === 1
  );
});
